-- Re-add grooms.showHandlingSkill (Equoria-ifhgq forward fix)
--
-- Migration 20260408210927_add_horse_title_breeding_columns contained a stray
-- autogenerated `ALTER TABLE "grooms" DROP COLUMN "showHandlingSkill";` that
-- dropped the column originally added by 20260403000000_add_groom_show_handling_skill.
-- schema.prisma still declares `showHandlingSkill String @default("novice")`, so
-- every DB built by `prisma migrate deploy` ends up missing the column while the
-- Prisma client queries it -> "The column `showHandlingSkill` does not exist".
--
-- This forward migration re-adds the column to match schema.prisma exactly
-- (TEXT NOT NULL DEFAULT 'novice'). IF NOT EXISTS makes it idempotent and safe on
-- any environment where the column somehow still exists. We do NOT edit the
-- already-applied 20260408210927 migration (editing applied history causes
-- checksum drift and would not repair already-migrated DBs).
ALTER TABLE "grooms" ADD COLUMN IF NOT EXISTS "showHandlingSkill" TEXT NOT NULL DEFAULT 'novice';
